+        if Bundle.main.bundleURL.pathExtension != "app" { return true }
         let env = ProcessInfo.processInfo.environment
         if env["XCTestConfigurationFilePath"] != nil { return true }
         if env["TESTING_LIBRARY_VERSION"] != nil { return true }

